from datetime import date

import pytest

from src.hello_world import Greeting, render_output, season_of, time_of_day


def test_greeting_stores_fields() -> None:
    greeting = Greeting("World", "Hello")
    assert greeting.recipient == "World"
    assert greeting.message == "Hello"


def test_greeting_formatted_contains_recipient_and_message() -> None:
    result = Greeting("Alice", "Hi").formatted()
    assert "Alice" in result
    assert "Hi" in result


def test_greeting_rejects_blank_recipient() -> None:
    with pytest.raises(ValueError):
        Greeting("", "Hello")


def test_greeting_rejects_blank_message() -> None:
    with pytest.raises(ValueError):
        Greeting("World", "  ")


def test_time_of_day_morning_for_hour_less_than_12() -> None:
    assert time_of_day(0) == "morning"
    assert time_of_day(11) == "morning"


def test_time_of_day_afternoon_for_hour_12_to_16() -> None:
    assert time_of_day(12) == "afternoon"
    assert time_of_day(16) == "afternoon"


def test_time_of_day_evening_for_hour_17_and_above() -> None:
    assert time_of_day(17) == "evening"
    assert time_of_day(23) == "evening"


@pytest.mark.parametrize(
    ("month", "expected"),
    [
        (12, "Winter"),
        (1, "Winter"),
        (2, "Winter"),
        (3, "Spring"),
        (4, "Spring"),
        (5, "Spring"),
        (6, "Summer"),
        (7, "Summer"),
        (8, "Summer"),
        (9, "Autumn"),
        (10, "Autumn"),
        (11, "Autumn"),
    ],
)
def test_season_of_returns_correct_season(month: int, expected: str) -> None:
    assert season_of(month) == expected


def test_render_output_contains_expected_sections() -> None:
    output = render_output(date(2026, 1, 15))
    assert "World" in output
    assert "Good afternoon" in output
    assert "Today's date : 2026-01-15 (Winter)" in output
    assert "Python version :" in output
